mapper.select:
SELECT FILE_SN, FILE_STRE_COURS, STRE_FILE_NM, ORIGNL_FILE_NM, FILE_EXTSN, FILE_SIZE
FROM FILE_DETAIL_INFO
WHERE FILE_SN = #{fileSn}

mapper.insert:
INSERT INTO FILE_DETAIL_INFO
	( FILE_SN
	  , FILE_STRE_COURS
	  , STRE_FILE_NM
	  , ORIGNL_FILE_NM
	  , FILE_EXTSN
	  , FILE_CN
	  , FILE_SIZE )
VALUES ( #{fileSn}
	  , #{fileStreCours}
	  , #{streFileNm}
	  , #{orignlFileNm}
	  , #{fileExtsn}
	  , #{fileCn}
	  , #{fileSize})
